5	export const RUNS_QUERY = gql`
6		query NodeRuns($first: Int, $after: String, $layer: RunLayer, $status: String) {
7			runs(first: $first, after: $after, layer: $layer, status: $status) {
8				edges {
9					node {
10						id
11						layer
12						status
13						projectID
14						beadId
15						startedAt
16						durationMs
17					}
18					cursor
19				}
20				pageInfo {
21					hasNextPage
22					endCursor
23				}
24				totalCount
25			}
26			projects {
27				edges {
28					node {
29						id
30						name
31					}
32				}
33			}
34		}
35	`
36	
37	export interface RunNode {
38		id: string
39		layer: string
40		status: string
41		projectID: string | null
42		beadId: string | null
43		startedAt: string | null
44		durationMs: number | null
45	}
46	
47	export interface RunEdge {
48		node: RunNode
49		cursor: string
50	}
51	
52	export interface PageInfo {
53		hasNextPage: boolean
54		endCursor: string | null
55	}
56	
57	export interface RunConnection {
58		edges: RunEdge[]
59		pageInfo: PageInfo
60		totalCount: number
61	}
62	
63	interface ProjectNode {
64		id: string
65		name: string
66	}
67	
68	interface QueryResult {
69		runs: RunConnection
70		projects: {
71			edges: Array<{ node: ProjectNode }>
72		}
73	}
74	
75	export const PAGE_SIZE = 50
76	
77	export const load: PageLoad = async ({ params, url, fetch }) => {
78		const layer = url.searchParams.get('layer') ?? null
79		const status = url.searchParams.get('status') ?? null
80	
81		const client = createClient(fetch as unknown as typeof globalThis.fetch)
82		const data = await client.request<QueryResult>(RUNS_QUERY, {
83			first: PAGE_SIZE,
84			layer: layer ?? undefined,
85			status: status ?? undefined
86		})
87	
88		const projectNames: Record<string, string> = {}
89		for (const { node } of data.projects.edges) {
90			projectNames[node.id] = node.name
91		}
92	
93		return {
94			nodeId: params.nodeId,
95			runs: data.runs,
96			projects: data.projects.edges.map((e) => e.node),
97			projectNames,
98			activeLayer: layer,
99			activeStatus: status
100		}
101	}
